EOF

sed -i 's/HiddenDefaultCmd bool/HiddenDefaultCmd bool
	// LimitCompletions is the maximum number of completion results to return.
	// If set to 0, no limit is applied.
	LimitCompletions int/' /workspace/repo/completions.go

