cat /tmp/patch.txt

sed -i '121a\
\
// SetLimitCompletions sets the maximum number of completion results to return.\
// If set to 0, no limit is applied.\
func (o *CompletionOptions) SetLimitCompletions(limit int) {\
	o.LimitCompletions = limit\
}' /workspace/repo/completions.go

python3 << 'EOF'
# Read the file
with open('/workspace/repo/completions.go', 'r') as f:
    content = f.read()

# Add the new functions before the closing of the file
new_functions = '''
// getFilterHidden returns the FilterHidden option from the command or its parents.
// It traverses up the command tree to find the nearest setting.
func getFilterHidden(cmd *Command) bool {
	for c := cmd; c != nil; c = c.parent {
		if c.CompletionOptions.FilterHidden {
			return true
		}
	}
	return false
}

// filterHiddenCompletions filters out completions that start with a dot (.).
func filterHiddenCompletions(completions []Completion) []Completion {
	result := make([]Completion, 0, len(completions))
	for _, c := range completions {
		if !strings.HasPrefix(c, ".") {
			result = append(result, c)
		}
	}
	return result
}

// SetFilterHidden sets the FilterHidden option on the CompletionOptions.
// This option prevents Cobra from providing completions that start with a dot (.)
// to the shell. This provides a consistent way to hide internal or configuration-
// related entries from shell tab-completion.
func (c *Command) SetFilterHidden(filterHidden bool) {
	c.CompletionOptions.FilterHidden = filterHidden
}
'''

# Find the last function in the file and add our functions after it
# We'll add after the last function (getEnvConfig)
last_func_end = content.rfind('}\n')
if last_func_end > 0:
    # Find the line break after the last function's closing brace
    insert_pos = last_func_end + 1
    content = content[:insert_pos] + new_functions + content[insert_pos:]

# Write the file back
with open('/workspace/repo/completions.go', 'w') as f:
    f.write(content)

print("Added helper functions")
EOF

cat >> /tmp/getLimitFunc.txt << 'EOF'

// getLimitCompletions returns the limit from the command hierarchy,
// searching from the command up to its parent until a non-zero limit is found.
func getLimitCompletions(cmd *Command) int {
	for c := cmd; c != nil; c = c.Parent() {
		if c.CompletionOptions.LimitCompletions > 0 {
			return c.CompletionOptions.LimitCompletions
		}
	}
	return 0
}

// applyLimitCompletions truncates the completions slice to the specified limit if limit > 0.
func applyLimitCompletions(completions []Completion, limit int) []Completion {
	if limit <= 0 {
		return completions
	}
	if len(completions) > limit {
		return completions[:limit]
	}
	return completions
}

EOF

